package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ObjectInputStream;
import java.io.ObjectStreamClass;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

class UnsafeAllocatorTest {

  @Test
  void testCreate_withUnsafe() throws Exception {
    // Setup mocks for sun.misc.Unsafe path
    Class<?> unsafeClass = mock(Class.class);
    Field unsafeField = mock(Field.class);
    Method allocateInstanceMethod = mock(Method.class);
    Object unsafeInstance = new Object();

    // Mock Class.forName to return unsafeClass when "sun.misc.Unsafe" is requested
    // Use a custom ClassLoader to override Class.forName is not possible easily,
    // so we simulate by reflection on UnsafeAllocator.create() directly.

    // Use reflection to access private static method create()
    Method createMethod = UnsafeAllocator.class.getDeclaredMethod("create");
    createMethod.setAccessible(true);

    // Because we cannot easily mock Class.forName or sun.misc.Unsafe in this environment,
    // we invoke create() and check the returned instance behavior.

    UnsafeAllocator allocator = (UnsafeAllocator) createMethod.invoke(null);
    assertNotNull(allocator);

    // Test that newInstance throws UnsupportedOperationException or works depending on environment
    // We expect UnsupportedOperationException in typical test environment

    assertThrows(UnsupportedOperationException.class, () -> allocator.newInstance(String.class));
  }

  @Test
  void testNewInstance_UnsupportedOperation() {
    UnsafeAllocator allocator = new UnsafeAllocator() {
      @Override
      public <T> T newInstance(Class<T> c) {
        throw new UnsupportedOperationException("Cannot allocate " + c);
      }
    };

    assertThrows(UnsupportedOperationException.class, () -> allocator.newInstance(Object.class));
  }

  @Test
  void testAssertInstantiable_withInterface() throws Exception {
    // Access private method assertInstantiable(Class<?>)
    Method assertInstantiableMethod = UnsafeAllocator.class.getDeclaredMethod("assertInstantiable", Class.class);
    assertInstantiableMethod.setAccessible(true);

    // Interface class should throw InstantiationException
    Class<?> interfaceClass = Runnable.class;
    InstantiationException ex = assertThrows(InstantiationException.class, () -> {
      assertInstantiableMethod.invoke(null, interfaceClass);
    });
    assertTrue(ex.getCause().getMessage().contains("interface"));
  }

  @Test
  void testAssertInstantiable_withAbstractClass() throws Exception {
    Method assertInstantiableMethod = UnsafeAllocator.class.getDeclaredMethod("assertInstantiable", Class.class);
    assertInstantiableMethod.setAccessible(true);

    abstract class AbstractClass {}
    InstantiationException ex = assertThrows(InstantiationException.class, () -> {
      assertInstantiableMethod.invoke(null, AbstractClass.class);
    });
    assertTrue(ex.getCause().getMessage().contains("abstract"));
  }

  @Test
  void testAssertInstantiable_withNonStaticMemberClass() throws Exception {
    Method assertInstantiableMethod = UnsafeAllocator.class.getDeclaredMethod("assertInstantiable", Class.class);
    assertInstantiableMethod.setAccessible(true);

    class Outer {
      class Inner {}
    }

    Class<?> innerClass = Outer.Inner.class;
    InstantiationException ex = assertThrows(InstantiationException.class, () -> {
      assertInstantiableMethod.invoke(null, innerClass);
    });
    assertTrue(ex.getCause().getMessage().contains("non-static"));
  }

  @Test
  void testAssertInstantiable_withInstantiableClass() throws Exception {
    Method assertInstantiableMethod = UnsafeAllocator.class.getDeclaredMethod("assertInstantiable", Class.class);
    assertInstantiableMethod.setAccessible(true);

    class Instantiable {}
    assertDoesNotThrow(() -> assertInstantiableMethod.invoke(null, Instantiable.class));
  }
}
